section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/practices-js-ts-stack.json",
  "type": "object",
  "required": [
    "strict_tsconfig",
    "esm_module",
    "flat_eslint",
    "ci_typecheck_step",
    "prettier_configured",
    "no_any_error"
  ],
  "properties": {
    "strict_tsconfig": {
      "type": "boolean",
      "const": true
    },
    "no_unchecked_indexed_access": {
      "type": "boolean"
    },
    "esm_module": {
      "type": "boolean",
      "const": true
    },
    "exports_map_present": {
      "type": "boolean"
    },
    "flat_eslint": {
      "type": "boolean",
      "const": true
    },
    "ci_typecheck_step": {
      "type": "boolean",
      "const": true
    },
    "prettier_configured": {
      "type": "boolean",
      "const": true
    },
    "no_any_error": {
      "type": "boolean",
      "const": true
    },
    "test_runner": {
      "enum": [
        "vitest",
        "jest",
        "node:test"
      ]
    }
  },
  "additionalProperties": false
}
